import React, { useState, useEffect } from 'react';

const STARS = Array.from({ length: 60 }, (_, i) => ({
  id: i, top: Math.random() * 100, left: Math.random() * 100,
  size: Math.random() * 2 + 0.5, duration: Math.random() * 3 + 2, delay: Math.random() * 4,
}));

function Landing() {
  const [owlBlink, setOwlBlink] = useState(false);
  const [scrolled, setScrolled]   = useState(false);

  useEffect(() => {
    const blink = setInterval(() => {
      setOwlBlink(true);
      setTimeout(() => setOwlBlink(false), 180);
    }, 3200);
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', onScroll);
    return () => { clearInterval(blink); window.removeEventListener('scroll', onScroll); };
  }, []);

  return (
    <div style={s.page}>

      {/* Stars */}
      <div style={{ position:'fixed', top:0, left:0, width:'100%', height:'100%', pointerEvents:'none', zIndex:0 }}>
        {STARS.map(star => (
          <div key={star.id} style={{
            position:'absolute', top:`${star.top}%`, left:`${star.left}%`,
            width:`${star.size}px`, height:`${star.size}px`,
            background:'#ffffff', borderRadius:'50%', opacity:0,
            animation:`twinkle ${star.duration}s ease-in-out infinite`,
            animationDelay:`${star.delay}s`,
          }}/>
        ))}
      </div>

      {/* Glow blobs */}
      <div style={{ position:'fixed', top:'-200px', left:'-150px', width:'700px', height:'700px', background:'radial-gradient(circle, rgba(34,197,94,0.07) 0%, transparent 70%)', pointerEvents:'none', zIndex:0 }}/>
      <div style={{ position:'fixed', bottom:'-200px', right:'-100px', width:'600px', height:'600px', background:'radial-gradient(circle, rgba(99,102,241,0.05) 0%, transparent 70%)', pointerEvents:'none', zIndex:0 }}/>

      {/* Navbar */}
      <nav style={{ position:'fixed', top:0, left:0, right:0, display:'flex', alignItems:'center', justifyContent:'space-between', padding:'16px 48px', zIndex:100, background: scrolled ? 'rgba(8,8,8,0.9)' : 'transparent', backdropFilter:'blur(12px)', borderBottom: scrolled ? '1px solid #1a1a1a' : 'none', transition:'all 0.3s' }}>
        <div style={{ display:'flex', alignItems:'center', gap:'10px' }}>
          <span style={{ fontSize:'22px' }}>🦉</span>
          <span style={{ fontSize:'20px', fontWeight:'700', color:'#ffffff', letterSpacing:'-0.3px', fontFamily:"'Poppins', sans-serif" }}>
            Dev<span style={{ color:'#22c55e' }}>Nest</span>
          </span>
          <span style={{ fontSize:'9px', fontWeight:'600', color:'#22c55e', background:'rgba(34,197,94,0.1)', border:'1px solid rgba(34,197,94,0.3)', borderRadius:'4px', padding:'2px 6px', letterSpacing:'1px' }}>BETA</span>
        </div>
        <div style={{ display:'flex', alignItems:'center', gap:'28px' }}>
          {['DSA Tracker','GitHub Analytics','AI Mentor','Portfolio'].map(link => (
            <span key={link} style={{ fontSize:'13px', color:'#9ca3af', cursor:'pointer', fontFamily:"'Poppins', sans-serif" }}>{link}</span>
          ))}
        </div>
        <a href="/login" style={{ padding:'9px 22px', background:'#22c55e', borderRadius:'8px', color:'#000', fontSize:'13px', fontWeight:'700', textDecoration:'none', fontFamily:"'Poppins', sans-serif", boxShadow:'0 4px 14px rgba(34,197,94,0.3)' }}>
          Login / Signup →
        </a>
      </nav>

      {/* Hero */}
      <div style={{ minHeight:'100vh', display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:'100px 48px 48px', position:'relative', zIndex:1 }}>

        {/* Top headline — center */}
        <div style={{ textAlign:'center', marginBottom:'48px' }}>
          <h1 style={{ fontSize:'68px', fontWeight:'800', color:'#ffffff', lineHeight:'1.05', letterSpacing:'-2.5px', marginBottom:'20px', fontFamily:"'Poppins', sans-serif" }}>
            Track, analyze &amp; share
          </h1>
          <p style={{ fontSize:'18px', color:'#9ca3af', lineHeight:'1.6', maxWidth:'560px', margin:'0 auto 32px', fontFamily:"'Poppins', sans-serif" }}>
            <strong style={{ color:'#ffffff' }}>Dev<span style={{ color:'#22c55e' }}>Nest</span></strong>
            {' '}helps you navigate and track your coding journey to success
          </p>
          <div style={{ display:'flex', gap:'12px', justifyContent:'center' }}>
            <a href="/login" style={{ padding:'14px 32px', background:'transparent', border:'1px solid #333', borderRadius:'10px', color:'#ffffff', fontSize:'14px', fontWeight:'500', textDecoration:'none', fontFamily:"'Poppins', sans-serif" }}>
              Profile Tracker
            </a>
            <a href="/register" style={{ padding:'14px 32px', background:'linear-gradient(135deg, #22c55e, #16a34a)', border:'none', borderRadius:'10px', color:'#000', fontSize:'14px', fontWeight:'700', textDecoration:'none', fontFamily:"'Poppins', sans-serif", boxShadow:'0 6px 24px rgba(34,197,94,0.35)' }}>
              Get Started →
            </a>
          </div>
        </div>

        {/* Visual row — owl + dashboard */}
        <div style={{ display:'flex', alignItems:'flex-end', justifyContent:'center', position:'relative', width:'100%', maxWidth:'900px' }}>

          {/* Owl — left, overlapping */}
          <div style={{ position:'absolute', left:'-20px', bottom:'0px', zIndex:10 }}>
            <svg width="190" height="220" viewBox="0 0 150 175" style={{ animation:'owlFloat 3.8s ease-in-out infinite', filter:'drop-shadow(0 20px 60px rgba(34,197,94,0.2))' }}>
              {/* Glow ring */}
              <circle cx="75" cy="75" r="52" fill="none" stroke="rgba(74,222,128,0.15)" strokeWidth="12" style={{ animation:'glowPulse 3s ease-in-out infinite' }}/>
              {/* Wings */}
              <path d="M52,110 Q18,88 15,128 Q28,145 58,138Z" fill="#162410"/>
              <path d="M52,110 Q22,92 20,125 Q32,138 56,132Z" fill="#1e3018"/>
              <path d="M98,110 Q132,88 135,128 Q122,145 92,138Z" fill="#162410"/>
              <path d="M98,110 Q128,92 130,125 Q118,138 94,132Z" fill="#1e3018"/>
              {/* Body */}
              <ellipse cx="75" cy="128" rx="40" ry="46" fill="#1e3018"/>
              <ellipse cx="75" cy="136" rx="26" ry="30" fill="#e8d5a0"/>
              {/* Body lines */}
              <path d="M61,124 Q75,127 89,124" stroke="#c8b078" strokeWidth="1.2" fill="none" opacity=".5"/>
              <path d="M59,132 Q75,135 91,132" stroke="#c8b078" strokeWidth="1" fill="none" opacity=".4"/>
              <path d="M62,140 Q75,143 88,140" stroke="#c8b078" strokeWidth=".8" fill="none" opacity=".3"/>
              {/* Head */}
              <circle cx="75" cy="68" r="44" fill="#1e3018"/>
              {/* Ear tufts */}
              <polygon points="56,38 46,10 64,34" fill="#162410"/>
              <polygon points="94,38 104,10 86,34" fill="#162410"/>
              <polygon points="56,36 50,14 62,31" fill="#243d1c"/>
              <polygon points="94,36 100,14 88,31" fill="#243d1c"/>
              {/* Eyes */}
              <circle cx="58" cy="65" r="19" fill="#f0e4c0"/>
              <circle cx="58" cy="65" r="14" fill="#f59e0b"/>
              <circle cx="58" cy="65" r="9" fill="#111"/>
              <circle cx="61" cy="62" r="3.5" fill="white" opacity=".9"/>
              <circle cx="60" cy="64" r="1.2" fill="white" opacity=".5"/>
              {owlBlink && <rect x="39" y="47" width="38" height="37" rx="19" fill="#1e3018"/>}
              <circle cx="92" cy="65" r="19" fill="#f0e4c0"/>
              <circle cx="92" cy="65" r="14" fill="#f59e0b"/>
              <circle cx="92" cy="65" r="9" fill="#111"/>
              <circle cx="95" cy="62" r="3.5" fill="white" opacity=".9"/>
              <circle cx="94" cy="64" r="1.2" fill="white" opacity=".5"/>
              {owlBlink && <rect x="73" y="47" width="38" height="37" rx="19" fill="#1e3018"/>}
              {/* Beak */}
              <polygon points="75,82 67,95 83,95" fill="#e07820"/>
              <line x1="75" y1="82" x2="75" y2="95" stroke="#b85c14" strokeWidth=".8"/>
              {/* Feet */}
              <path d="M58,170 L52,177 M58,170 L57,178 M58,170 L63,177" stroke="#2d4a20" strokeWidth="2.2" strokeLinecap="round" fill="none"/>
              <path d="M92,170 L86,177 M92,170 L91,178 M92,170 L97,177" stroke="#2d4a20" strokeWidth="2.2" strokeLinecap="round" fill="none"/>
              <rect x="32" y="166" width="86" height="7" rx="3.5" fill="#4a2e1a"/>
              <rect x="27" y="164" width="96" height="5" rx="2.5" fill="#6b3f24"/>
            </svg>
          </div>

          {/* Dashboard Preview */}
          <div style={{ width:'580px', marginLeft:'160px', background:'#0d0d0d', border:'1px solid #1f1f1f', borderRadius:'20px', padding:'20px', boxShadow:'0 40px 100px rgba(0,0,0,0.7)', position:'relative', zIndex:5 }}>

            {/* Top bar */}
            <div style={{ display:'flex', alignItems:'center', gap:'6px', marginBottom:'16px' }}>
              <div style={{ width:'10px', height:'10px', borderRadius:'50%', background:'#ef4444' }}/>
              <div style={{ width:'10px', height:'10px', borderRadius:'50%', background:'#f59e0b' }}/>
              <div style={{ width:'10px', height:'10px', borderRadius:'50%', background:'#22c55e' }}/>
              <div style={{ flex:1, background:'#1a1a1a', borderRadius:'6px', height:'24px', marginLeft:'8px' }}/>
            </div>

            {/* Profile row */}
            <div style={{ display:'flex', alignItems:'center', gap:'12px', marginBottom:'16px', padding:'12px', background:'#0a0a0a', borderRadius:'12px', border:'1px solid #1a1a1a' }}>
              <div style={{ width:'42px', height:'42px', borderRadius:'50%', background:'linear-gradient(135deg, #22c55e, #16a34a)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'18px', fontWeight:'700', color:'#000' }}>S</div>
              <div>
                <div style={{ fontSize:'14px', fontWeight:'600', color:'#fff', fontFamily:"'Poppins', sans-serif" }}>Shrey Jain ✅</div>
                <div style={{ fontSize:'11px', color:'#22c55e', fontFamily:"'Poppins', sans-serif" }}>@shreyjain</div>
              </div>
              <div style={{ marginLeft:'auto', fontSize:'11px', color:'#6b7280', fontFamily:"'Poppins', sans-serif" }}>Last updated today</div>
            </div>

            {/* Stats row */}
            <div style={{ display:'grid', gridTemplateColumns:'repeat(3, 1fr)', gap:'10px', marginBottom:'16px' }}>
              {[
                { label:'Total Questions', value:'25',  color:'#ffffff' },
                { label:'Active Days',     value:'12',  color:'#ffffff' },
                { label:'AI Readiness',    value:'78%', color:'#22c55e' },
              ].map(stat => (
                <div key={stat.label} style={{ background:'#0a0a0a', border:'1px solid #1a1a1a', borderRadius:'12px', padding:'14px', textAlign:'center' }}>
                  <div style={{ fontSize:'26px', fontWeight:'700', color: stat.color, fontFamily:"'Poppins', sans-serif" }}>{stat.value}</div>
                  <div style={{ fontSize:'10px', color:'#6b7280', marginTop:'2px', fontFamily:"'Poppins', sans-serif" }}>{stat.label}</div>
                </div>
              ))}
            </div>

            {/* DSA rings */}
            <div style={{ background:'#0a0a0a', border:'1px solid #1a1a1a', borderRadius:'12px', padding:'14px', marginBottom:'12px' }}>
              <div style={{ fontSize:'11px', color:'#6b7280', marginBottom:'12px', fontFamily:"'Poppins', sans-serif" }}>Problems Solved</div>
              <div style={{ display:'flex', gap:'20px', justifyContent:'center' }}>
                {[
                  { label:'Easy',   val:80, color:'#22c55e', r: 138 },
                  { label:'Medium', val:45, color:'#f59e0b', r: 138 },
                  { label:'Hard',   val:20, color:'#ef4444',  r: 138 },
                ].map(ring => (
                  <div key={ring.label} style={{ display:'flex', flexDirection:'column', alignItems:'center', gap:'4px' }}>
                    <svg width="64" height="64" viewBox="0 0 64 64">
                      <circle cx="32" cy="32" r="24" fill="none" stroke="#1a1a1a" strokeWidth="5"/>
                      <circle cx="32" cy="32" r="24" fill="none" stroke={ring.color} strokeWidth="5"
                        strokeDasharray={`${ring.val * 1.508} 150.8`}
                        strokeLinecap="round"
                        transform="rotate(-90 32 32)"
                        style={{ transition:'stroke-dasharray 1s ease' }}
                      />
                      <text x="32" y="37" textAnchor="middle" fill={ring.color} fontSize="12" fontWeight="700" fontFamily="Poppins">{ring.val}%</text>
                    </svg>
                    <span style={{ fontSize:'10px', color:'#6b7280', fontFamily:"'Poppins', sans-serif" }}>{ring.label}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Heatmap */}
            <div style={{ background:'#0a0a0a', border:'1px solid #1a1a1a', borderRadius:'12px', padding:'12px' }}>
              <div style={{ fontSize:'10px', color:'#6b7280', marginBottom:'8px', fontFamily:"'Poppins', sans-serif" }}>Contribution Activity</div>
              <div style={{ display:'flex', flexWrap:'wrap', gap:'3px' }}>
                {Array.from({ length: 56 }, (_, i) => {
                  const intensity = Math.random();
                  return (
                    <div key={i} style={{
                      width:'9px', height:'9px', borderRadius:'2px',
                      background: intensity > 0.6
                        ? `rgba(34,197,94,${intensity})`
                        : intensity > 0.3
                        ? 'rgba(34,197,94,0.2)'
                        : '#1a1a1a',
                    }}/>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Floating DevNest Card */}
          <div style={{ position:'absolute', right:'-10px', top:'-20px', background:'#0d0d0d', border:'1px solid #1f1f1f', borderRadius:'16px', padding:'16px', width:'150px', boxShadow:'0 20px 60px rgba(0,0,0,0.6)', zIndex:10 }}>
            <div style={{ fontSize:'10px', color:'#22c55e', fontWeight:'600', marginBottom:'10px', fontFamily:"'Poppins', sans-serif" }}>🦉 DevNest CARD</div>
            <div style={{ width:'44px', height:'44px', borderRadius:'50%', background:'linear-gradient(135deg, #22c55e, #16a34a)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'18px', fontWeight:'700', color:'#000', margin:'0 auto 8px' }}>S</div>
            <div style={{ fontSize:'12px', fontWeight:'600', color:'#fff', textAlign:'center', fontFamily:"'Poppins', sans-serif" }}>Shrey Jain ✅</div>
            <div style={{ fontSize:'10px', color:'#6b7280', textAlign:'center', marginBottom:'12px', fontFamily:"'Poppins', sans-serif" }}>@shreyjain</div>
            <div style={{ display:'flex', justifyContent:'space-around', borderTop:'1px solid #1a1a1a', paddingTop:'10px' }}>
              <div style={{ textAlign:'center' }}>
                <div style={{ fontSize:'15px', fontWeight:'700', color:'#fff', fontFamily:"'Poppins', sans-serif" }}>25</div>
                <div style={{ fontSize:'9px', color:'#6b7280', fontFamily:"'Poppins', sans-serif" }}>Questions</div>
              </div>
              <div style={{ width:'1px', background:'#1f1f1f' }}/>
              <div style={{ textAlign:'center' }}>
                <div style={{ fontSize:'15px', fontWeight:'700', color:'#22c55e', fontFamily:"'Poppins', sans-serif" }}>7</div>
                <div style={{ fontSize:'9px', color:'#6b7280', fontFamily:"'Poppins', sans-serif" }}>Streak</div>
              </div>
            </div>
          </div>
        </div>

        {/* Stats row bottom */}
        <div style={{ display:'flex', gap:'48px', marginTop:'48px', justifyContent:'center' }}>
          {[
            { num:'25+',  label:'DSA Problems'   },
            { num:'AI',   label:'Powered Mentor' },
            { num:'100%', label:'Free to Use'    },
            { num:'1',    label:'Platform'       },
          ].map(stat => (
            <div key={stat.label} style={{ textAlign:'center' }}>
              <div style={{ fontSize:'26px', fontWeight:'700', color:'#22c55e', fontFamily:"'Poppins', sans-serif" }}>{stat.num}</div>
              <div style={{ fontSize:'11px', color:'#6b7280', fontFamily:"'Poppins', sans-serif" }}>{stat.label}</div>
            </div>
          ))}
        </div>
      </div>

      <style>{`
        @keyframes twinkle {
          0%,100%{opacity:0;transform:scale(0.5)}
          50%{opacity:0.7;transform:scale(1)}
        }
        @keyframes owlFloat {
          0%,100%{transform:translateY(0px)}
          50%{transform:translateY(-14px)}
        }
        @keyframes glowPulse {
          0%,100%{opacity:0.3;r:52}
          50%{opacity:0.8;r:55}
        }
        * { box-sizing:border-box; margin:0; padding:0; }
      `}</style>
    </div>
  );
}

export default Landing;
